    if not order_data or not isinstance(order_data, dict):
        try:
            logger.error("Invalid order data: received type=%s", type(order_data).__name__)
        except Exception:
            pass
        raise ValueError("Invalid order data")

    order_id = order_data.get("order_id")
    items = order_data.get("items", [])
    customer_email = order_data.get("customer_email")
    payment_method = order_data.get("payment_method")
    coupon_code = order_data.get("coupon_code")

    if not order_id or not items:
        try:
            logger.error("Missing order_id or items: order_id=%s, items_present=%s", order_id, bool(items))
        except Exception:
            pass
        raise ValueError("Missing order_id or items")

    # Calculate total
    total = 0
    for item in items:
        price = item.get("price", 0)
        qty = item.get("quantity", 1)
        total += price * qty

    # Apply coupon
    discount = 0
    if coupon_code:
        if coupon_code == "SAVE10":
            discount = total * 0.10
            try:
                logger.info("Applied coupon SAVE10: discount=%.2f on total=%.2f", discount, total)
            except Exception:
                pass
        elif coupon_code == "SAVE20":
            discount = total * 0.20
            try:
                logger.info("Applied coupon SAVE20: discount=%.2f on total=%.2f", discount, total)
            except Exception:
                pass
        elif coupon_code == "FLAT50":
            discount = min(50, total)
            try:
                logger.info("Applied coupon FLAT50: discount=%.2f on total=%.2f", discount, total)
            except Exception:
                pass
        else:
            try:
                logger.warning("Unknown coupon code '%s' provided; ignoring", coupon_code)
            except Exception:
                pass
            pass  # Unknown coupon, silently ignored

    final_total = total - discount

    # Payment processing (simulated)
    if payment_method == "credit_card":
        cc_number = order_data.get("cc_number", "")
        masked_cc = _mask_cc(cc_number)
        try:
            logger.debug("Selected payment method: credit_card (masked: %s), final_total=%.2f", masked_cc, final_total)
        except Exception:
            pass
        if len(cc_number) != 16:
            try:
                logger.error("Invalid credit card number for order %s: length=%d", order_id, len(cc_number))
            except Exception:
                pass
            raise ValueError("Invalid credit card number")
        charge_result = _charge_card(cc_number, final_total)
    elif payment_method == "paypal":
        try:
            logger.debug(
                "Selected payment method: paypal, customer_email(masked)=%s, final_total=%.2f",
                _mask_email(customer_email) if customer_email else None,
                final_total,
            )
        except Exception:
            pass
        charge_result = _charge_paypal(customer_email, final_total)
    else:
        try:
            logger.error("Unsupported payment method for order %s: %s", order_id, payment_method)
        except Exception:
            pass
        raise ValueError(f"Unsupported payment method: {payment_method}")

    if not charge_result.get("success"):
        err = charge_result.get("error", "unknown")
        try:
            logger.error("Payment processing failed for order %s: %s", order_id, err)
        except Exception:
            pass
        raise RuntimeError(f"Payment failed: {err}")

    # Send confirmation email
    if customer_email:
        try:
            logger.info("Sending order confirmation email for order_id=%s", order_id)
            _send_email(
                customer_email,
                f"Order {order_id} Confirmed",
                f"Your order total: ${final_total:.2f}"
            )
            try:
                logger.info("Order confirmation email dispatched for order_id=%s", order_id)
            except Exception:
                pass
        except Exception:
            try:
                logger.warning("Failed to send confirmation email for order %s (non-critical error)", order_id)
            except Exception:
                pass
            pass  # Email failure is not critical
    else:
        try:
            logger.warning("Skipping confirmation email for order %s: no customer_email provided", order_id)
        except Exception:
            pass

    result = {
        "order_id": order_id,
        "status": "completed",
        "total": final_total,
        "discount": discount,
        "items_count": len(items),
    }

    try:
        logger.debug(
            "Exiting process_order successfully for order_id=%s with result summary: status=%s, total=%.2f, discount=%.2f, items_count=%d, email_attempted=%s",
            order_id,
            result["status"],
            result["total"],
            result["discount"],
            result["items_count"],
            bool(customer_email),
        )
    except Exception:
        pass

    return result


def _charge_card(cc_number, amount):
    masked = _mask_cc(cc_number)
    try:
        logger.debug("Entering _charge_card: masked_cc=%s, amount=%.2f", masked, amount)
    except Exception:
        pass

    # Simulate credit card charge
    if amount <= 0:
        try:
            logger.warning("_charge_card received invalid amount: %.2f", amount)
        except Exception:
            pass
        ret = {"success": False, "error": "Invalid amount"}
        try:
            logger.debug("Exiting _charge_card with failure: %s", ret)
        except Exception:
            pass
        return ret

    ret = {"success": True, "transaction_id": f"txn_{datetime.now().timestamp()}"}
    try:
        logger.debug("Exiting _charge_card successfully: transaction_id=%s", ret.get("transaction_id"))
    except Exception:
        pass
    return ret


def _charge_paypal(email, amount):
    masked_email = _mask_email(email)
    try:
        logger.debug("Entering _charge_paypal: masked_email=%s, amount=%.2f", masked_email, amount)
    except Exception:
        pass

    # Simulate PayPal charge
    if not email:
        try:
            logger.warning("_charge_paypal called without email")
        except Exception:
            pass
        ret = {"success": False, "error": "No email for PayPal"}
        try:
            logger.debug("Exiting _charge_paypal with failure: %s", ret)
        except Exception:
            pass
        return ret

    ret = {"success": True, "transaction_id": f"pp_{datetime.now().timestamp()}"}
    try:
        logger.debug("Exiting _charge_paypal successfully: transaction_id=%s", ret.get("transaction_id"))
    except Exception:
        pass
    return ret


def _send_email(to_addr, subject, body):
    masked_to = _mask_email(to_addr)
    try:
        logger.debug(
            "Entering _send_email: to=%s, subject=%s, body_length=%d",
            masked_to,
            subject,
            len(body) if body else 0,
        )
    except Exception:
        pass

    msg = MIMEText(body)
    msg["Subject"] = subject
    msg["From"] = SMTP_USER
    msg["To"] = to_addr

    try:
        logger.info("Connecting to SMTP server %s:%s to send email for subject='%s'", SMTP_HOST, SMTP_PORT, subject)
    except Exception:
        pass

    with smtplib.SMTP(SMTP_HOST, SMTP_PORT) as server:
        server.starttls()
        server.login(SMTP_USER, SMTP_PASS)
        server.send_message(msg)

    try:
        logger.info("Successfully sent email to %s with subject '%s'", masked_to, subject)
    except Exception:
        pass

    try:
        logger.debug("Exiting _send_email")
    except Exception:
        pass
